<?php namespace GitFlow\Orchestrator; use Psr\Http\Client\ClientInterface; use Psr\Http\Message\RequestFactoryInterface; use RuntimeException; class GitHubClient { private ClientInterface $httpClient; private RequestFactoryInterface $requestFactory; private string $token; private string $baseUrl = "https://api.github.com"; public function __construct(ClientInterface $httpClient, RequestFactoryInterface $requestFactory, string $token) { $this->httpClient = $httpClient; $this->requestFactory = $requestFactory; $this->token = $token; } public function triggerWorkflow(string $owner, string $repo, string $workflowId, array $inputs): bool { $url = "$this->baseUrl/repos/$owner/$repo/actions/workflows/$workflowId/dispatches"; $payload = json_encode(['ref' => 'main', 'inputs' => $inputs]); $request = $this->requestFactory->createRequest('POST', $url) ->withHeader('Authorization', "Bearer $this->token") ->withHeader('Accept', 'application/vnd.github.v3+json') ->withHeader('Content-Type', 'application/json') ->withBody($this->createStream($payload)); $response = $this->httpClient->sendRequest($request); if ($response->getStatusCode() !== 204) { throw new RuntimeException("Failed to trigger workflow: HTTP " . $response->getStatusCode()); } return true; } private function createStream(string $content) { $stream = fopen('php://temp', 'r+'); fwrite($stream, $content); rewind($stream); return $stream; } }